import Foundation
import os.log

// MARK: - Log Level

enum LogLevel: Int, Comparable {
    case verbose = 0
    case debug = 1
    case info = 2
    case warning = 3
    case error = 4
    case critical = 5
    case none = 6
    
    var prefix: String {
        switch self {
        case .verbose:  return "📝 VERBOSE"
        case .debug:    return "🔍 DEBUG"
        case .info:     return "ℹ️ INFO"
        case .warning:  return "⚠️ WARNING"
        case .error:    return "❌ ERROR"
        case .critical: return "🔥 CRITICAL"
        case .none:     return ""
        }
    }
    
    var osLogType: OSLogType {
        switch self {
        case .verbose, .debug: return .debug
        case .info:            return .info
        case .warning:         return .default
        case .error:           return .error
        case .critical:        return .fault
        case .none:            return .default
        }
    }
    
    static func < (lhs: LogLevel, rhs: LogLevel) -> Bool {
        return lhs.rawValue < rhs.rawValue
    }
}

// MARK: - Data Redaction Utilities

struct DataRedactor {
    
    /// Masks an email: "john.doe@example.com" -> "j******e@e****e.com"
    static func redactEmail(_ email: String?) -> String {
        guard let email = email, !email.isEmpty else { return "[no-email]" }
        
        let components = email.split(separator: "@", maxSplits: 1)
        guard components.count == 2 else { return "[invalid-email]" }
        
        let localPart = String(components[0])
        let domainPart = String(components[1])
        
        let maskedLocal = maskString(localPart, revealFirst: 1, revealLast: 1)
        let domainComponents = domainPart.split(separator: ".")
        let maskedDomain = domainComponents.map { part in
            maskString(String(part), revealFirst: 1, revealLast: 1)
        }.joined(separator: ".")
        
        return "\(maskedLocal)@\(maskedDomain)"
    }
    
    /// Masks a user ID: "user_abc123def456" -> "user_ab...f456"
    static func redactUserID(_ userID: String?) -> String {
        guard let userID = userID, !userID.isEmpty else { return "[no-user-id]" }
        if userID.count <= 6 { return "***" }
        let prefix = String(userID.prefix(4))
        let suffix = String(userID.suffix(4))
        return "\(prefix)...\(suffix)"
    }
    
    /// Completely redacts a token, showing only length and last 4 chars
    static func redactToken(_ token: String?) -> String {
        guard let token = token, !token.isEmpty else { return "[no-token]" }
        if token.count <= 4 { return "[tok:***]" }
        let suffix = String(token.suffix(4))
        return "[tok:len=\(token.count)...\(suffix)]"
    }
    
    /// Redacts sensitive fields from a dictionary payload
    static func redactPayload(_ payload: [String: Any]?) -> [String: Any] {
        guard let payload = payload else { return [:] }
        
        let sensitiveKeys: Set<String> = [
            "password", "passwd", "secret", "token", "access_token",
            "refresh_token", "authorization", "api_key", "apikey",
            "credit_card", "card_number", "cvv", "ssn",
            "social_security", "pin", "otp", "mfa_code",
            "private_key", "session_token", "cookie"
        ]
        
        let piiKeys: Set<String> = [
            "email", "email_address", "phone", "phone_number",
            "address", "street", "zip", "postal_code",
            "date_of_birth", "dob", "full_name", "first_name", "last_name"
        ]
        
        var redacted: [String: Any] = [:]
        
        for (key, value) in payload {
            let lowercasedKey = key.lowercased()
            
            if sensitiveKeys.contains(lowercasedKey) {
                redacted[key] = "[REDACTED]"
            } else if lowercasedKey.contains("token") || lowercasedKey.contains("secret") || lowercasedKey.contains("password") {
                redacted[key] = "[REDACTED]"
            } else if piiKeys.contains(lowercasedKey) {
                if lowercasedKey.contains("email"), let emailValue = value as? String {
                    redacted[key] = redactEmail(emailValue)
                } else {
                    redacted[key] = "[PII-REDACTED]"
                }
            } else if let nestedDict = value as? [String: Any] {
                redacted[key] = redactPayload(nestedDict)
            } else if let arrayValue = value as? [[String: Any]] {
                redacted[key] = arrayValue.map { redactPayload($0) }
            } else {
                redacted[key] = value
            }
        }
        
        return redacted
    }
    
    /// Redacts URL query parameters that may contain sensitive data
    static func redactURL(_ url: URL?) -> String {
        guard let url = url else { return "[no-url]" }
        
        let sensitiveParams: Set<String> = [
            "token", "access_token", "api_key", "key", "secret",
            "password", "session", "auth"
        ]
        
        guard var components = URLComponents(url: url, resolvingAgainstBaseURL: false) else {
            return url.absoluteString
        }
        
        if let queryItems = components.queryItems {
            components.queryItems = queryItems.map { item in
                if sensitiveParams.contains(item.name.lowercased()) {
                    return URLQueryItem(name: item.name, value: "[REDACTED]")
                }
                return item
            }
        }
        
        return components.string ?? url.absoluteString
    }
    
    private static func maskString(_ string: String, revealFirst: Int, revealLast: Int) -> String {
        guard string.count > revealFirst + revealLast else {
            return String(repeating: "*", count: string.count)
        }
        let prefix = String(string.prefix(revealFirst))
        let suffix = String(string.suffix(revealLast))
        let maskCount = max(string.count - revealFirst - revealLast, 3)
        return "\(prefix)\(String(repeating: "*", count: maskCount))\(suffix)"
    }
