// MARK: - Log Entry

struct LogEntry: Codable {
    let id: UUID
    let timestamp: Date
    let level: String
    let category: String
    let message: String
    let metadata: [String: String]?
    let file: String
    let function: String
    let line: Int
    
    var formattedTimestamp: String {
        let formatter = DateFormatter()
        formatter.dateFormat = "yyyy-MM-dd HH:mm:ss.SSS"
        return formatter.string(from: timestamp)
    }
}

// MARK: - Log Category

enum LogCategory: String {
    case authentication = "AUTH"
    case api = "API"
    case userData = "USER_DATA"
    case navigation = "NAV"
    case lifecycle = "LIFECYCLE"
    case performance = "PERF"
    case error = "ERROR"
    case analytics = "ANALYTICS"
    case general = "GENERAL"
}

// MARK: - Log Storage (In-Memory Ring Buffer)

final class LogStorage {
    private let maxEntries: Int
    private var entries: [LogEntry] = []
    private let queue = DispatchQueue(label: "com.app.logstorage", attributes: .concurrent)
    
    init(maxEntries: Int = 1000) {
        self.maxEntries = maxEntries
    }
    
    func append(_ entry: LogEntry) {
        queue.async(flags: .barrier) {
            self.entries.append(entry)
            if self.entries.count > self.maxEntries {
                self.entries.removeFirst(self.entries.count - self.maxEntries)
            }
        }
    }
    
    func getEntries(category: LogCategory? = nil, level: LogLevel? = nil, limit: Int = 100) -> [LogEntry] {
        queue.sync {
            var filtered = entries
            if let category = category {
                filtered = filtered.filter { $0.category == category.rawValue }
            }
            if let level = level {
                filtered = filtered.filter { $0.level == level.prefix }
            }
            return Array(filtered.suffix(limit))
        }
    }
    
    func clear() {
        queue.async(flags: .barrier) {
            self.entries.removeAll()
        }
    }
    
    func exportForCrashReport() -> String {
        let recentEntries = getEntries(limit: 50)
        return recentEntries.map { entry in
            "[\(entry.formattedTimestamp)] [\(entry.level)] [\(entry.category)] \(entry.message)"
        }.joined(separator: "\n")
    }
}

